+#[no_mangle]
+pub extern "C" fn init(dims: u8, metric: u8, core_id: u8) {
+    unsafe {
+        HNSW.count = 0;
+        HNSW.dims = dims.min(MAX_DIMS as u8);
+        HNSW.metric = match metric { 1 => Metric::Cosine, 2 => Metric::Dot, _ => Metric::L2 };
+        HNSW.core_id = core_id;
+    }
