+/// Reset SNN state for all neurons
+#[no_mangle]
+pub extern "C" fn snn_reset() {
+    unsafe {
+        let mut i = 0;
+        while i < MAX_VECTORS {
+            MEMBRANE[i] = V_REST;
+            THRESHOLD[i] = 1.0;
+            LAST_SPIKE[i] = -1000.0;
+            REFRAC[i] = 0.0;
+            SPIKES[i] = false;
+            i += 1;
+        }
+        SIM_TIME = 0.0;
+    }
+}
