+}
+
+/// Set firing threshold for a neuron
+#[no_mangle]
+pub extern "C" fn snn_set_threshold(idx: u8, t: f32) {
+    if idx < MAX_VECTORS as u8 { unsafe { THRESHOLD[idx as usize] = t; } }
+}
