+/// Inject current into a neuron (adds to membrane potential)
+#[no_mangle]
+pub extern "C" fn snn_inject(idx: u8, current: f32) {
+    if idx < MAX_VECTORS as u8 { unsafe { MEMBRANE[idx as usize] += current; } }
+}
