+/// Get spike status (1 if spiked last step, 0 otherwise)
+#[no_mangle]
+pub extern "C" fn snn_spiked(idx: u8) -> u8 {
+    if idx < MAX_VECTORS as u8 { unsafe { SPIKES[idx as usize] as u8 } } else { 0 }
+}
