+// ============ Distance Unit - Pipelined L2 ============
+module distance_unit #(
+    parameter DATA_WIDTH = 16,
+    parameter MAX_DIMS = 64
+)(
+    input  wire                     clk,
+    input  wire                     rst_n,
+    input  wire                     start,
+    input  wire [5:0]               dims,
+    input  wire [DATA_WIDTH-1:0]    a_data,
+    input  wire [DATA_WIDTH-1:0]    b_data,
+    output reg  [31:0]              distance,
+    output reg                      done
+);
+
+reg [5:0] dim_idx;
+reg [31:0] accum;
+reg computing;
+
+always @(posedge clk or negedge rst_n) begin
+    if (!rst_n) begin
+        done <= 1'b0;
+        computing <= 1'b0;
+        accum <= 0;
+    end else begin
+        if (start && !computing) begin
+            computing <= 1'b1;
+            dim_idx <= 0;
+            accum <= 0;
+            done <= 1'b0;
+        end else if (computing) begin
+            if (dim_idx < dims) begin
+                // Compute squared difference
+                reg signed [DATA_WIDTH:0] diff;
+                diff = $signed(a_data) - $signed(b_data);
+                accum <= accum + (diff * diff);
+                dim_idx <= dim_idx + 1;
+            end else begin
+                distance <= accum;
+                done <= 1'b1;
+                computing <= 1'b0;
+            end
+        end else begin
+            done <= 1'b0;
+        end
+    end
+end
+
+endmodule
